INSERT INTO kv (key, value) VALUES ('profile', '{"name":"Alex Rivera","handle":"alex","email":"alex@buildstack.dev","avatarUrl":"https://i.pravatar.cc/160?img=12","bio":"Backend engineer. I write about systems, databases, and the occasional system design detour."}') ON CONFLICT(key) DO UPDATE SET value = excluded.value;
INSERT INTO kv (key, value) VALUES ('posts', '[{"id":"me1","title":"Mechanical engineering: designing parts that survive real loads","author":"Nora Kim","authorHandle":"nora","date":"Jul 8, 2026","readTime":"5 min read","tags":["mechanical engineering","design","materials"],"likes":74,"liked":false,"excerpt":"A practical look at turning force, fatigue, and tolerances into parts that can handle daily use.","body":["Mechanical engineering starts with loads. Before picking a material or drawing a bracket, define the forces, cycles, temperature range, and failure modes the part will face.","Good designs leave room for manufacturing variation. A perfect CAD model is less useful than a part with tolerances that a shop can actually hit.","The best review question is simple: what breaks first, and how would we know before it reaches a customer?"],"comments":[]},{"id":"me2","title":"Thermal management for compact machines","author":"Nora Kim","authorHandle":"nora","date":"Jul 7, 2026","readTime":"6 min read","tags":["mechanical engineering","thermal","systems"],"likes":68,"liked":false,"excerpt":"Heat sinks, airflow paths, and enclosure choices matter long before the prototype starts running hot.","body":["Thermal problems are system problems. A hot motor, battery, or controller is often telling you that the enclosure, airflow, and duty cycle were designed separately.","Start with a heat budget and a path to ambient air. Every interface adds resistance, and every blocked vent turns into a field issue.","Testing across real operating cycles catches failures that a bench fan can hide."],"comments":[]},{"id":"me3","title":"Tolerances are product decisions","author":"Nora Kim","authorHandle":"nora","date":"Jul 6, 2026","readTime":"4 min read","tags":["mechanical engineering","manufacturing","quality"],"likes":59,"liked":false,"excerpt":"Tighter tolerances are expensive, so engineering teams should reserve them for the dimensions that matter.","body":["A tolerance is a cost decision disguised as a drawing note.","Identify the functional dimensions first.","A good drawing tells manufacturing where precision matters and where it does not."],"comments":[]},{"id":"ee1","title":"Electrical engineering: reading schematics like systems","author":"Maya Chen","authorHandle":"maya","date":"Jul 8, 2026","readTime":"5 min read","tags":["electrical engineering","circuits","hardware"],"likes":88,"liked":false,"excerpt":"A schematic is more than symbols. It is a map of power, signals, assumptions, and failure boundaries.","body":["Read a schematic from power entry outward.","Most board failures come from assumptions.","Annotating intent in reviews catches more bugs than checking values alone."],"comments":[]},{"id":"ee2","title":"Power budgets for embedded devices","author":"Maya Chen","authorHandle":"maya","date":"Jul 7, 2026","readTime":"6 min read","tags":["electrical engineering","embedded","power"],"likes":92,"liked":false,"excerpt":"Battery life depends on sleep states, regulator choices, radios, and the boring math between them.","body":["Power budgets should start as spreadsheets and end as measurements.","Regulator efficiency changes with load.","Instrument early."],"comments":[]},{"id":"ee3","title":"Grounding mistakes that create noisy products","author":"Maya Chen","authorHandle":"maya","date":"Jul 6, 2026","readTime":"4 min read","tags":["electrical engineering","pcb","signal integrity"],"likes":77,"liked":false,"excerpt":"Noise is often a layout issue hiding behind firmware symptoms and flaky sensor readings.","body":["Ground is not magic. It is a return path.","Keep noisy switching loops small.","Inspect the current path before blaming the sensor."],"comments":[]},{"id":"ne1","title":"Nuclear engineering: designing with defense in depth","author":"Ethan Park","authorHandle":"ethan","date":"Jul 8, 2026","readTime":"6 min read","tags":["nuclear engineering","safety","systems"],"likes":81,"liked":false,"excerpt":"Nuclear systems rely on layered controls where no single assumption is allowed to carry safety alone.","body":["Defense in depth means every critical function has layers.","The engineering mindset is conservative because uncertainty compounds.","A strong design asks what happens after each barrier fails."],"comments":[]},{"id":"ne2","title":"Radiation shielding as an optimization problem","author":"Ethan Park","authorHandle":"ethan","date":"Jul 7, 2026","readTime":"5 min read","tags":["nuclear engineering","radiation","materials"],"likes":63,"liked":false,"excerpt":"Shielding design balances source terms, geometry, material selection, maintenance access, and cost.","body":["Shielding is not just adding mass.","Geometry matters because distance is powerful.","The best plan supports inspection and maintenance."],"comments":[]},{"id":"ne3","title":"What reactor control teaches every engineer","author":"Ethan Park","authorHandle":"ethan","date":"Jul 6, 2026","readTime":"5 min read","tags":["nuclear engineering","controls","operations"],"likes":70,"liked":false,"excerpt":"Slow feedback, strict procedures, and conservative margins make nuclear controls a study in disciplined engineering.","body":["Control systems in nuclear environments reward patience and clarity.","Instrumentation, procedures, and training are part of the design.","Good controls make the safe action obvious."],"comments":[]},{"id":"ce1","title":"Civil engineering: designing bridges for maintenance","author":"Samir Patel","authorHandle":"samir","date":"Jul 8, 2026","readTime":"5 min read","tags":["civil engineering","structures","maintenance"],"likes":84,"liked":false,"excerpt":"A bridge is not finished when it opens. Access, inspection, drainage, and repairability shape its real lifespan.","body":["Civil engineering lives on long timelines.","Drainage details often decide durability.","Design reviews should include maintainers."],"comments":[]},{"id":"ce2","title":"Stormwater systems and urban tradeoffs","author":"Samir Patel","authorHandle":"samir","date":"Jul 7, 2026","readTime":"6 min read","tags":["civil engineering","water","infrastructure"],"likes":73,"liked":false,"excerpt":"Managing stormwater is part hydraulics, part land use, and part planning for storms that keep changing.","body":["Stormwater design starts with rainfall and risk.","Green infrastructure still needs maintenance.","The best systems combine pipes, ponds, grading, and policy."],"comments":[]},{"id":"ce3","title":"Soil reports are design documents","author":"Samir Patel","authorHandle":"samir","date":"Jul 6, 2026","readTime":"4 min read","tags":["civil engineering","geotechnical","foundations"],"likes":65,"liked":false,"excerpt":"Foundations fail when teams treat subsurface conditions as background information instead of active constraints.","body":["A soil report tells you what uncertainty the project is standing on.","Bearing capacity and groundwater shape cost.","Geotechnical risk is easiest to manage early."],"comments":[]},{"id":"se1","title":"Software engineering: keeping services understandable","author":"Alex Rivera","authorHandle":"alex","date":"Jul 8, 2026","readTime":"5 min read","tags":["software engineering","architecture","backend"],"likes":119,"liked":false,"excerpt":"The best services are not just scalable. They are easy to reason about when production is noisy.","body":["A service boundary should make ownership and failure modes clearer.","Logs, metrics, traces, and runbooks are part of the codebase.","Quality shows up when a new teammate can explain the system."],"comments":[]},{"id":"se2","title":"API contracts that age well","author":"Alex Rivera","authorHandle":"alex","date":"Jul 7, 2026","readTime":"6 min read","tags":["software engineering","api","systems"],"likes":106,"liked":false,"excerpt":"Good APIs make change possible by being explicit about ownership, compatibility, and failure behavior.","body":["An API is a promise.","Document examples for real workflows.","Compatibility is easier when contracts are tested automatically."],"comments":[]},{"id":"se3","title":"Refactoring without stopping delivery","author":"Alex Rivera","authorHandle":"alex","date":"Jul 6, 2026","readTime":"5 min read","tags":["software engineering","refactoring","teams"],"likes":94,"liked":false,"excerpt":"Refactoring works best when it is sliced into reversible changes that reduce risk each week.","body":["Big rewrites feel clean until they meet production.","Start by adding tests around behavior.","A refactor is successful when future changes become boring."],"comments":[]},{"id":"ae1","title":"Aerospace engineering: mass budgets drive everything","author":"Iris Stone","authorHandle":"iris","date":"Jul 8, 2026","readTime":"5 min read","tags":["aerospace engineering","structures","flight"],"likes":97,"liked":false,"excerpt":"Every gram competes with strength, thermal control, power, payload, and manufacturing reality.","body":["Aerospace design is a chain of mass trades.","Margins matter, but excess margin has a cost.","A good mass budget is updated constantly."],"comments":[]},{"id":"ae2","title":"Wind tunnel data and simulation trust","author":"Iris Stone","authorHandle":"iris","date":"Jul 7, 2026","readTime":"6 min read","tags":["aerospace engineering","aerodynamics","simulation"],"likes":89,"liked":false,"excerpt":"CFD and physical testing are strongest when each is used to challenge the other.","body":["Simulation gives speed and visibility.","Disagreements are where learning starts.","Trust grows when models are validated across the envelope."],"comments":[]},{"id":"ae3","title":"Flight software depends on hardware discipline","author":"Iris Stone","authorHandle":"iris","date":"Jul 6, 2026","readTime":"5 min read","tags":["aerospace engineering","avionics","software"],"likes":82,"liked":false,"excerpt":"Reliable flight systems come from clear interfaces between sensors, actuators, timing, and control logic.","body":["Flight software cannot rescue unclear hardware assumptions.","Interfaces should be boring and explicit.","The system is ready when failure cases are practiced."],"comments":[]},{"id":"che1","title":"Chemical engineering: scaling reactions safely","author":"Leah Grant","authorHandle":"leah","date":"Jul 8, 2026","readTime":"6 min read","tags":["chemical engineering","process","safety"],"likes":76,"liked":false,"excerpt":"A reaction that behaves in a flask can become a heat, mixing, and pressure problem at plant scale.","body":["Scale changes chemistry because heat transfer and mixing behave differently.","Process safety reviews should happen early.","The best scale-up plans add staged validation."],"comments":[]},{"id":"che2","title":"Process control for stable production","author":"Leah Grant","authorHandle":"leah","date":"Jul 7, 2026","readTime":"5 min read","tags":["chemical engineering","controls","manufacturing"],"likes":69,"liked":false,"excerpt":"Stable plants depend on sensors, control loops, operator displays, and clear responses to drift.","body":["Process control starts with understanding what must stay inside limits.","A loop is useful when the sensor is reliable.","Operators need trend and context."],"comments":[]},{"id":"che3","title":"Material balances make problems visible","author":"Leah Grant","authorHandle":"leah","date":"Jul 6, 2026","readTime":"4 min read","tags":["chemical engineering","mass balance","operations"],"likes":61,"liked":false,"excerpt":"Before optimizing a process, account for every stream entering, leaving, reacting, and accumulating.","body":["A material balance catches impossible assumptions.","Balances make yield and waste visible.","They create a shared language across teams."],"comments":[]},{"id":"re1","title":"Robotics engineering: sensors are part of the control loop","author":"Owen Brooks","authorHandle":"owen","date":"Jul 8, 2026","readTime":"5 min read","tags":["robotics engineering","controls","sensors"],"likes":101,"liked":false,"excerpt":"A robot only controls the world it can measure, and every sensor has latency, noise, and blind spots.","body":["Robotics engineering begins with uncertainty.","Control loops need to account for latency and drift.","A robot becomes dependable when perception, planning, and actuation are tested as one system."],"comments":[]},{"id":"re2","title":"Designing robot arms for serviceability","author":"Owen Brooks","authorHandle":"owen","date":"Jul 7, 2026","readTime":"5 min read","tags":["robotics engineering","mechanisms","maintenance"],"likes":87,"liked":false,"excerpt":"Robots that are easy to repair spend more time doing useful work and less time waiting for specialists.","body":["Serviceability is an engineering feature.","A beautiful mechanism that takes hours to open punishes field teams.","Design the repair path while CAD is flexible."],"comments":[]},{"id":"re3","title":"Simulation is not the finish line for robots","author":"Owen Brooks","authorHandle":"owen","date":"Jul 6, 2026","readTime":"6 min read","tags":["robotics engineering","simulation","testing"],"likes":93,"liked":false,"excerpt":"Simulation speeds iteration, but the real world adds friction, backlash, lighting, wear, and surprises.","body":["Simulation is a multiplier, not a substitute.","Hardware-in-the-loop testing closes the gap.","The goal is knowing which failures the sim cannot show."],"comments":[]}]') ON CONFLICT(key) DO UPDATE SET value = excluded.value;
INSERT INTO kv (key, value) VALUES ('portfolio', '[{"title":"Incident Timeline Engine","stack":"TypeScript / Postgres / Redis","summary":"A collaborative timeline for on-call reviews with deploy markers, alert imports, and action item tracking.","metric":"42% faster postmortems","image":"https://images.unsplash.com/photo-1551288049-bebda4e38f71?auto=format&fit=crop&w=900&q=80"},{"title":"Query Plan Inspector","stack":"Go / SQL / WASM","summary":"A browser tool that turns database explain plans into readable bottleneck reports for app engineers.","metric":"18 slow paths removed","image":"https://images.unsplash.com/photo-1555949963-aa79dcee981c?auto=format&fit=crop&w=900&q=80"},{"title":"CI Signal Dashboard","stack":"React / Workers / SQLite","summary":"A build health surface that groups flaky failures, ownership, and recovery trends for large test suites.","metric":"31% fewer reruns","image":"https://images.unsplash.com/photo-1461749280684-dccba630e2f6?auto=format&fit=crop&w=900&q=80"}]') ON CONFLICT(key) DO UPDATE SET value = excluded.value;
INSERT INTO kv (key, value) VALUES ('friends', '[{"name":"Priya Nair","handle":"priya","role":"Reliability engineer focused on CI systems and test infrastructure.","avatar":"https://i.pravatar.cc/160?img=47"},{"name":"Dana Osei","handle":"dana","role":"Backend engineer building schedulers, queues, and Rust services.","avatar":"https://i.pravatar.cc/160?img=32"},{"name":"Lena Vogt","handle":"lena","role":"Product-minded engineer writing about scope, teams, and delivery.","avatar":"https://i.pravatar.cc/160?img=5"},{"name":"Marcus Feld","handle":"marcus","role":"Database specialist who helps teams make query latency boring.","avatar":"https://i.pravatar.cc/160?u=marcus"}]') ON CONFLICT(key) DO UPDATE SET value = excluded.value;
INSERT INTO kv (key, value) VALUES ('ads', '[{"title":"Ship observability in one sprint","copy":"TraceFlow gives backend teams logs, traces, and alerts without dashboard sprawl."},{"title":"Typed APIs without busywork","copy":"SchemaForge generates SDKs, docs, and contract tests from one source of truth."},{"title":"Cloud cost reviews for engineers","copy":"MeterMind finds idle spend and noisy services before finance asks."}]') ON CONFLICT(key) DO UPDATE SET value = excluded.value;
